import { queryOptions } from "@tanstack/react-query";
import type { DocsManifest } from "./docs-meta";

export interface RegistryFile {
	target: string;
	content: string;
}

export interface RegistryJson {
	dependencies: string[];
	registryDependencies: string[];
	files: RegistryFile[];
	demo?: string;
}

async function fetchJson<T>(url: string): Promise<T> {
	const res = await fetch(url);
	if (!res.ok) throw new Error(`Failed to fetch ${url}: ${res.status}`);
	return res.json() as Promise<T>;
}

export const docsKeys = {
	all: ["docs"] as const,
	manifest: () => ["docs", "manifest"] as const,
	registry: (name: string) => ["docs", "registry", name] as const,
};

export const docsQueries = {
	manifest: () =>
		queryOptions<DocsManifest>({
			queryKey: docsKeys.manifest(),
			queryFn: () => fetchJson<DocsManifest>("/docs/components.json"),
			staleTime: 5 * 60 * 1000,
		}),
	registry: (name: string) =>
		queryOptions<RegistryJson | null>({
			queryKey: docsKeys.registry(name),
			queryFn: async () => {
				try {
					return await fetchJson<RegistryJson>(`/reg/${name}.json`);
				} catch {
					return null;
				}
			},
			staleTime: 5 * 60 * 1000,
		}),
};

export type DocsStatus = "stable" | "beta" | "experimental";

export interface DocsAccessibility {
	keyboard?: string[];
	aria?: string[];
}

export interface DocsMeta {
	title: string;
	description: string;
	category: string;
	status?: DocsStatus;
	keywords?: string[];
	related?: string[];
	accessibility?: DocsAccessibility;
}

export interface DocsManifestExample {
	name: string;
	source: string;
}

export interface DocsManifestDemo {
	source: string;
}

export interface DocsManifestItem {
	title: string;
	description: string;
	category: string;
	status: DocsStatus | undefined;
	keywords: string[] | undefined;
	related: string[] | undefined;
	accessibility: DocsAccessibility | undefined;
	registryName: string;
	demo: DocsManifestDemo | undefined;
	examples: DocsManifestExample[];
}

export type DocsManifest = Record<string, DocsManifestItem>;

import { QueryClient } from "@tanstack/react-query";

export const queryClient = new QueryClient({
	defaultOptions: {
		queries: {
			staleTime: 5 * 60 * 1000,
			gcTime: 30 * 60 * 1000,
		},
	},
});

import { codeToHtml } from "../../shiki.bundle";

type Lang =
	| "typescript"
	| "ts"
	| "js"
	| "jsx"
	| "json"
	| "bash"
	| "css"
	| "html"
	| "md";

const LANGUAGES: Lang[] = [
	"typescript",
	"ts",
	"js",
	"jsx",
	"json",
	"bash",
	"css",
	"html",
	"md",
];

export async function highlightCode(
	code: string,
	language: string,
): Promise<string> {
	try {
		const lang = LANGUAGES.includes(language as Lang) ? language : "typescript";
		return codeToHtml(code, {
			lang,
			theme: "github-dark",
		});
	} catch {
		return escapeHtml(code);
	}
}

function escapeHtml(code: string): string {
	return `<pre class="shiki"><code>${code
		.replace(/&/g, "&amp;")
		.replace(/</g, "&lt;")
		.replace(/>/g, "&gt;")}</code></pre>`;
}

